<script>
function erroViagem(msg){document.getElementById('erro-viagem-texto').textContent=msg;document.getElementById('erro-viagem').style.display='flex';document.getElementById('resultado-viagem').classList.remove('show');}
function limparErroViagem(){document.getElementById('erro-viagem').style.display='none';}
function calcularTempoViagem(){const distancia=parseFloat(document.getElementById('distancia-viagem').value);const velocidade=parseFloat(document.getElementById('velocidade-viagem').value);limparErroViagem();if(isNaN(distancia)||isNaN(velocidade)||distancia<=0||velocidade<=0){erroViagem('Informe distï¿½ncia e velocidade mï¿½dia maiores que zero.');return;}const horas=distancia/velocidade;const horasInteiras=Math.floor(horas);const minutos=Math.round((horas-horasInteiras)*60);document.getElementById('viagem-horas').textContent=fmtNum(horas,2)+' h';document.getElementById('viagem-formatado').textContent=horasInteiras+'h '+minutos+'min';document.getElementById('viagem-detalhe').textContent='Fï¿½rmula aplicada: distï¿½ncia ï¿½ velocidade mï¿½dia.';showResult('resultado-viagem');}
function limparTempoViagem(){document.getElementById('distancia-viagem').value='';document.getElementById('velocidade-viagem').value='';document.getElementById('resultado-viagem').classList.remove('show');limparErroViagem();}
function copiarTempoViagem(button){if(!document.getElementById('resultado-viagem').classList.contains('show')){erroViagem('Calcule o tempo antes de copiar o resultado.');return;}copyToClipboard('Tempo da viagem: '+document.getElementById('viagem-formatado').textContent,button);}
</script>
